def best_portfolio():
    probs = {'soft': 0.60, 'stag': 0.15, 'recession': 0.25}
    asset_returns = {
        'T': {'soft': 4.0, 'stag': 2.0, 'recession': 6.0},
        'C': {'soft': 6.0, 'stag': -4.0, 'recession': 1.0},
        'E': {'soft': 24.0, 'stag': -8.0, 'recession': -22.0},
        'V': {'soft': 16.0, 'stag': 5.0, 'recession': -30.0}
    }

    best = None

    # Exhaustive enumeration over 10% increments (0 to 1.0 represented as 0 to 10)
    for wt in range(11):
        for wc in range(11):
            for we in range(11):
                for wv in range(11):
                    if wt + wc + we + wv != 10:
                        continue

                    t, c, e, v = wt / 10.0, wc / 10.0, we / 10.0, wv / 10.0

                    # Board constraints
                    if v > 0.2: continue
                    if e > 0.5: continue
                    if t + c + e < 0.8: continue

                    # Scenario returns
                    r_soft = t*asset_returns['T']['soft'] + c*asset_returns['C']['soft'] + e*asset_returns['E']['soft'] + v*asset_returns['V']['soft']
                    r_stag = t*asset_returns['T']['stag'] + c*asset_returns['C']['stag'] + e*asset_returns['E']['stag'] + v*asset_returns['V']['stag']
                    r_rec  = t*asset_returns['T']['recession'] + c*asset_returns['C']['recession'] + e*asset_returns['E']['recession'] + v*asset_returns['V']['recession']

                    # Recession floor constraint
                    if r_rec < -8.0:
                        continue

                    exp_ret = probs['soft']*r_soft + probs['stag']*r_stag + probs['recession']*r_rec

                    # Optimization & tie-breaking
                    if best is None:
                        best = {'weights': {'T': t, 'C': c, 'E': e, 'V': v},
                                'soft': r_soft, 'stag': r_stag, 'recession': r_rec, 'expected': exp_ret}
                    else:
                        if exp_ret > best['expected'] + 1e-9:
                            best = {'weights': {'T': t, 'C': c, 'E': e, 'V': v},
                                    'soft': r_soft, 'stag': r_stag, 'recession': r_rec, 'expected': exp_ret}
                        elif abs(exp_ret - best['expected']) <= 1e-9:
                            if r_stag > best['stag'] + 1e-9:
                                best = {'weights': {'T': t, 'C': c, 'E': e, 'V': v},
                                        'soft': r_soft, 'stag': r_stag, 'recession': r_rec, 'expected': exp_ret}
                            elif abs(r_stag - best['stag']) <= 1e-9:
                                if t > best['weights']['T'] + 1e-9:
                                    best = {'weights': {'T': t, 'C': c, 'E': e, 'V': v},
                                            'soft': r_soft, 'stag': r_stag, 'recession': r_rec, 'expected': exp_ret}

    # Round outputs as specified
    for k in ['soft', 'stag', 'recession', 'expected']:
        best[k] = round(best[k], 2)
    for k in best['weights']:
        best['weights'][k] = round(best['weights'][k], 1)

    return best
