import json
import math

def monthly_payment(principal, annual_rate, months):
 if months <= 0:
 raise ValueError("months must be positive")
 monthly_rate = annual_rate / 12.0
 if monthly_rate == 0.0:
 return principal / months
 return principal * monthly_rate / (1.0 - (1.0 + monthly_rate) ** (-months))

def remaining_balance(principal, annual_rate, months, payments_made):
 if months <= 0:
 raise ValueError("months must be positive")
 if payments_made < 0:
 raise ValueError("payments_made must be non-negative")
 if payments_made >= months:
 return 0.0

 monthly_rate = annual_rate / 12.0
 if monthly_rate == 0.0:
 return max(principal - (principal / months) * payments_made, 0.0)

 full_growth = (1.0 + monthly_rate) ** months
 paid_growth = (1.0 + monthly_rate) ** payments_made
 balance = principal * (full_growth - paid_growth) / (full_growth - 1.0)
 return max(balance, 0.0)

def build_offer(principal, annual_rate, points_pct, lender_fees, term_months, hold_months):
 payment = monthly_payment(principal, annual_rate, term_months)
 balance_after_hold = remaining_balance(principal, annual_rate, term_months, hold_months)
 principal_repaid = principal - balance_after_hold
 interest_paid = payment * hold_months - principal_repaid
 points_paid = principal * points_pct / 100.0
 total_financing_cost = interest_paid + points_paid + lender_fees

 return {
 "monthly_payment": payment,
 "remaining_balance_after_96_months": balance_after_hold,
 "principal_repaid_during_hold": principal_repaid,
 "interest_paid_during_hold": interest_paid,
 "points_paid_upfront": points_paid,
 "lender_fees": lender_fees,
 "total_financing_cost": total_financing_cost,
 }

def money(value):
 return round(value, 2)

def serialize_offer(offer):
 return {key: money(value) for key, value in offer.items()}

def main():
 principal = 496000.0
 term_months = 360
 hold_months = 96
 lender_fees = 1800.0

 offer_a_raw = build_offer(principal, 0.061, 0.0, lender_fees, term_months, hold_months)
 offer_b_raw = build_offer(principal, 0.0575, 1.5, lender_fees, term_months, hold_months)

 monthly_savings_b_vs_a = offer_a_raw["monthly_payment"] - offer_b_raw["monthly_payment"]
 extra_upfront_points_b_vs_a = offer_b_raw["points_paid_upfront"] - offer_a_raw["points_paid_upfront"]

 if monthly_savings_b_vs_a > 0:
 break_even_month = math.ceil(extra_upfront_points_b_vs_a / monthly_savings_b_vs_a)
 else:
 break_even_month = None

 recommended_offer = (
 "Offer A"
 if offer_a_raw["total_financing_cost"] <= offer_b_raw["total_financing_cost"]
 else "Offer B"
 )

 result = {
 "offer_A": serialize_offer(offer_a_raw),
 "offer_B": serialize_offer(offer_b_raw),
 "break_even_month_B_vs_A": break_even_month,
 "recommended_offer_for_96_month_holding_period": recommended_offer,
 }

 print(json.dumps(result, indent=2))

if __name__ == "__main__":
 main()
